import Foundation

/// Holds the static therapy content for the Functional Skills section of CogniLink.
struct FrenchFunctionalSkillsExerciseData {
    
    /// The complete collection of all 6 Functional Skills exercises.
    static let allExercises: [Exercise] = [
        exercise1,
        exercise2,
        exercise3,
        exercise4,
        exercise5,
        exercise6
    ]
    
    // MARK: - Exercise 1: Safety Scenarios
    private static let exercise1 = Exercise(
        id: UUID(),
        title: "Scénarios de sécurité",
        instructions: "Lisez chaque scénario. Décrivez ce que vous feriez. Appuyez sur \"Afficher la réponse\" pour voir la meilleure réponse modèle.",
        section: .functionalSkills,
        type: .openEnded,
        trackedType: nil,
        difficulty: .medium,
        items: [
            ExerciseItem(id: UUID(), prompt: "Vous glissez dans l'escalier de la cave et pensez vous être tordu la cheville.", options: [], correctAnswer: "Restez immobile. N'essayez pas de marcher dessus. Appelez à l'aide. Si vous êtes seul, composez le 911 ou utilisez votre téléphone. Ne bougez que si vous pouvez le faire en toute sécurité.", explanation: "Rester immobile et demander de l'aide évite d'aggraver une éventuelle fracture ou entorse en portant du poids sur la cheville blessée."),
            ExerciseItem(id: UUID(), prompt: "Un début d'incendie se déclare dans la cuisine alors que vous faites frire des aliments.", options: [], correctAnswer: "N'utilisez JAMAIS d'eau sur un feu de graisse ou d'huile, car cela propage les flammes. Éteignez le brûleur. Étouffez le feu avec un couvercle métallique ou une plaque à pâtisserie. Utilisez un extincteur si nécessaire.", explanation: "L'eau projetée sur une huile enflammée se vaporise instantanément et propulse des gouttelettes brûlantes dans toutes les directions, alors que priver le feu d'oxygène avec un couvercle l'éteint sans danger."),
            ExerciseItem(id: UUID(), prompt: "Vous recevez un courriel indiquant qu'il y a eu une erreur sur votre compte bancaire et vous proposant une récompense pour la corriger.", options: [], correctAnswer: "Ne répondez pas. Ne cliquez sur aucun lien. Il s'agit d'une tentative d'hameçonnage (phishing). Supprimez immédiatement le courriel.", explanation: "Les banques légitimes ne récompensent jamais les clients par courriel pour signaler une erreur de compte ; ce schéma est un classique de l'hameçonnage visant à voler des identifiants."),
            ExerciseItem(id: UUID(), prompt: "Vous vous réveillez au milieu de la nuit avec une douleur intense et persistante dans la poitrine.", options: [], correctAnswer: "Composez immédiatement le 911. N'attendez pas de voir si la douleur passe. Une douleur thoracique peut être le signe d'un infarctus. Restez calme en attendant les secours.", explanation: "Une douleur thoracique persistante et nocturne est un symptôme classique d'infarctus, où chaque minute d'attente réduit les chances de survie du muscle cardiaque."),
            ExerciseItem(id: UUID(), prompt: "Quelqu'un vous appelle en prétendant que votre ordinateur est infecté par un virus et propose de le réparer gratuitement à distance.", options: [], correctAnswer: "Raccrochez immédiatement. C'est une arnaque au support technique. Les entreprises légitimes ne font jamais d'appels non sollicités de ce genre. Ne donnez jamais accès à votre ordinateur.", explanation: "Les entreprises informatiques légitimes ne contactent jamais spontanément les particuliers pour signaler une infection virale ; c'est une arnaque conçue pour obtenir un accès à distance à l'ordinateur."),
            ExerciseItem(id: UUID(), prompt: "En rentrant chez vous, vous remarquez qu'une fenêtre a été brisée et que la porte d'entrée est entrouverte.", options: [], correctAnswer: "N'entrez pas. Éloignez-vous immédiatement de la maison. Composez le 911 depuis un endroit sûr. Attendez que la police arrive et inspecte les lieux avant d'entrer.", explanation: "Entrer dans une maison potentiellement cambriolée expose à un affrontement avec l'intrus ; il vaut mieux laisser la police sécuriser les lieux en premier."),
            ExerciseItem(id: UUID(), prompt: "Un appel téléphonique automatisé vous demande de confirmer votre numéro de sécurité sociale pour éviter le gel de vos prestations.", options: [], correctAnswer: "Raccrochez. C'est une tentative d'usurpation d'identité. Les administrations gouvernementales ne demandent jamais de numéro de sécurité sociale par appel automatisé.", explanation: "Les agences gouvernementales américaines ne demandent jamais de vérifier un numéro de sécurité sociale par un appel automatisé, ce qui trahit une tentative de vol d'identité."),
            ExerciseItem(id: UUID(), prompt: "Vous recevez un SMS urgent refusant ou affirmant que votre compte de chèques est bloqué et qu'il faut cliquer sur un lien pour le réactiver.", options: [], correctAnswer: "Ne cliquez pas sur le lien. Appelez directement votre banque en utilisant le numéro officiel figurant au dos de votre carte de débit pour vérifier l'état de votre compte.", explanation: "Cliquer sur un lien reçu par SMS peut mener à un faux site imitant la banque ; contacter directement le numéro officiel évite de transmettre ses identifiants à des fraudeurs."),
            ExerciseItem(id: UUID(), prompt: "Vous conduisez sur l'autoroute et vous commencez soudainement à vous sentir très étourdi et confus.", options: [], correctAnswer: "Rangez-vous sur le côté de la route ou sur la bande d'arrêt d'urgence dès que vous pouvez le faire en toute sécurité. Allumez vos feux de détresse et appelez le 911 ou un proche.", explanation: "S'arrêter en sécurité avant que les symptômes n'empirent réduit le risque d'accident, car conduire en état de confusion met en danger le conducteur et les autres usagers."),
            ExerciseItem(id: UUID(), prompt: "Un démarcheur se présente chez vous en disant travailler pour la compagnie d'électricité locale (comme PG&E ou SCE) mais refuse de vous montrer sa carte professionnelle.", options: [], correctAnswer: "Ne le laissez pas entrer. Demandez-lui de montrer sa carte à travers la fenêtre. Appelez directement le service client officiel de la compagnie pour confirmer sa visite.", explanation: "Un vrai employé d'une compagnie d'électricité accepte toujours de montrer son identification ; le refus est un signe classique d'usurpation utilisée pour s'introduire dans un domicile."),
            ExerciseItem(id: UUID(), prompt: "Vous trouvez un comprimé blanc non identifié sur le sol de votre salle de bains.", options: [], correctAnswer: "Ne le prenez pas. Jetez-le de manière sécurisée en le rapportant à une pharmacie locale disposant d'un bac de collecte. Ne le jetez pas dans les toilettes ni à la poubelle ordinaire.", explanation: "Un comprimé non identifié peut être dangereux pour les enfants, les animaux ou par accident ; les pharmacies disposent de bacs prévus pour une élimination sécurisée des médicaments."),
            ExerciseItem(id: UUID(), prompt: "Votre détecteur de fumée émet un bip sonore aigu toutes les minutes.", options: [], correctAnswer: "Cela signifie que la pile est faible. Remplacez la pile immédiatement. Ne retirez jamais la pile sans en réinstaller une nouvelle tout de suite.", explanation: "Un bip répétitif et espacé est le signal standard de pile faible sur les détecteurs de fumée, distinct de l'alarme continue signalant un incendie réel."),
            ExerciseItem(id: UUID(), prompt: "Vous réalisez que vous venez de prendre accidentellement une double dose de vos médicaments prescrits pour le cœur.", options: [], correctAnswer: "Appelez immédiatement le centre antipoison au 1-800-222-1222 ou composez le 911. Gardez le flacon de médicament à portée de main pour donner les détails exacts.", explanation: "Un surdosage de médicaments cardiaques peut provoquer des complications graves rapidement ; le centre antipoison peut donner des instructions précises immédiates selon le médicament exact."),
            ExerciseItem(id: UUID(), prompt: "Quelqu'un vous appelle en pleurant, prétendant être votre petit-fils en voyage, disant qu'il est en prison et qu'il a besoin que vous lui envoyiez de l'argent immédiatement.", options: [], correctAnswer: "Raccrochez. C'est l'arnaque classique du 'grand-parent'. Appelez directement votre petit-fils ou ses parents sur leur numéro habituel pour vérifier. N'envoyez jamais d'argent.", explanation: "Cette arnaque repose sur la panique pour empêcher toute vérification ; rappeler directement le proche sur son numéro habituel permet de confirmer qu'il s'agit d'un mensonge."),
            ExerciseItem(id: UUID(), prompt: "Vous constatez soudainement qu'un côté de votre visage s'affaisse, que votre bras est faible et que vous avez du mal à articuler vos mots.", options: [], correctAnswer: "Composez le 911 immédiatement. Ce sont les signes précurseurs d'un accident vasculaire cérébral (AVC). Pensez à l'acronyme VITE : Visage affaissé, Inertie d'un membre, Trouble de la parole, Éteindre le doute (appeler le 911).", explanation: "Un affaissement facial, une faiblesse d'un bras et des troubles de la parole sont les signes typiques d'un AVC, où un traitement rapide limite les dommages cérébraux permanents."),
            ExerciseItem(id: UUID(), prompt: "L'alarme de votre détecteur de monoxyde de carbone se déclenche en continu.", options: [], correctAnswer: "Sortez immédiatement de la maison avec tous les occupants et les animaux. Ne vous arrêtez pas pour ramasser vos affaires. Appelez le 911 depuis l'extérieur.", explanation: "Le monoxyde de carbone est un gaz inodore et toxique qui peut provoquer une perte de conscience rapide ; sortir immédiatement évite toute exposition prolongée avant de chercher de l'aide."),
            ExerciseItem(id: UUID(), prompt: "Un appelant se présente comme un agent du fisc américain (IRS) et menace de vous faire arrêter si vous ne payez pas immédiatement des impôts en retard avec des cartes-cadeaux.", options: [], correctAnswer: "Raccrochez. Le fisc ne demande jamais de paiement immédiat par téléphone, encore moins par cartes-cadeaux ou virement. C'est une fraude grossière.", explanation: "Le fisc américain communique par courrier officiel et ne réclame jamais de paiement instantané par cartes-cadeaux, une méthode utilisée uniquement par les escrocs."),
            ExerciseItem(id: UUID(), prompt: "Vous tombez dans votre jardin, vous vous cognez la tête et vous vous sentez désorienté et pris de nausées.", options: [], correctAnswer: "Appelez le 911 ou demandez à un voisin d'appeler les secours. Une confusion après un traumatisme crânien nécessite une évaluation médicale d'urgence. Ne vous couchez pas pour dormir.", explanation: "La confusion et les nausées après un choc à la tête peuvent signaler une commotion ou une hémorragie interne nécessitant une évaluation médicale urgente plutôt qu'un simple repos."),
            ExerciseItem(id: UUID(), prompt: "Votre nouvelle ordonnance contient des pilules de couleur et de forme différentes de celles que vous prenez d'habitude, bien que le nom soit similaire.", options: [], correctAnswer: "Ne les prenez pas. Contactez immédiatement votre pharmacien pour vérifier s'il s'agit d'une erreur de préparation ou d'un changement de fabricant pour un médicament générique.", explanation: "Un changement d'apparence d'un médicament habituel peut indiquer une erreur de dosage ou de substance ; le pharmacien peut vérifier avant toute prise risquée."),
            ExerciseItem(id: UUID(), prompt: "Dans le parking d'un supermarché en fin de journée, vous remarquez qu'une personne vous suit de près alors que vous vous dirigez vers votre voiture.", options: [], correctAnswer: "Ne montez pas dans votre voiture. Retournez dans le magasin bien éclairé ou approchez-vous d'un groupe de personnes. Demandez l'aide de la sécurité du magasin ou appelez la police.", explanation: "S'éloigner vers un lieu peuplé et éclairé dissuade un agresseur potentiel, alors que monter seul dans sa voiture dans un parking isolé augmente la vulnérabilité."),
            ExerciseItem(id: UUID(), prompt: "Vous sentez une odeur permanente de brûlé ou de plastique fondu provenant de l'intérieur d'une prise électrique murale.", options: [], correctAnswer: "N'utilisez plus la prise. Coupez le disjoncteur correspondant si vous savez le faire, évacuez la pièce et appelez les pompiers au 911. Cela indique un début d'incendie électrique mural.", explanation: "Une odeur de brûlé provenant d'une prise indique une surchauffe des câbles pouvant déclencher un incendie électrique caché dans les murs, d'où l'urgence de couper l'alimentation."),
            ExerciseItem(id: UUID(), prompt: "Vous recevez un message sur votre répondeur affirmant que votre numéro de carte verte ou votre statut d'immigration est suspendu.", options: [], correctAnswer: "Ignorez ce message et raccrochez. Les services d'immigration américains (USCIS) ne suspendent pas les statuts par téléphone de cette manière et n'appellent pas pour demander de l'argent.", explanation: "Les services d'immigration américains communiquent par courrier officiel, jamais par message vocal menaçant réclamant de l'argent pour éviter une suspension de statut."),
            ExerciseItem(id: UUID(), prompt: "Vous réalisez en vous couchant que vous avez oublié une bougie allumée sur la table basse du salon.", options: [], correctAnswer: "Levez-vous immédiatement pour aller l'éteindre complètement. Ne laissez jamais une bougie brûler sans surveillance, car c'est une cause majeure d'incendie domestique.", explanation: "Une flamme sans surveillance peut facilement enflammer un objet proche pendant le sommeil, ce qui en fait une cause fréquente d'incendies domestiques évitables."),
            ExerciseItem(id: UUID(), prompt: "Un entrepreneur se présente spontanément à votre domicile et propose de réparer votre toiture pour un prix très bas, uniquement en espèces et sans contrat écrit.", options: [], correctAnswer: "Refusez poliment et fermez la porte. Les entrepreneurs légitimes fournissent des devis écrits détaillés et ne demandent pas de paiement complet en espèces à l'avance sans contrat.", explanation: "L'absence de contrat écrit et l'exigence de paiement en espèces sont des signes classiques d'arnaque aux travaux, sans recours possible en cas de travail mal fait."),
            ExerciseItem(id: UUID(), prompt: "Vous trouvez un chien errant qui semble blessé et qui grogne légèrement sur le trottoir.", options: [], correctAnswer: "Ne tentez pas de le caresser ou de le déplacer vous-même. Un animal blessé et apeuré peut mordre pour se défendre. Appelez le service local de contrôle des animaux.", explanation: "Un animal blessé et effrayé peut mordre par réflexe de défense même envers une personne bienveillante ; des professionnels formés savent le manipuler sans risque."),
            ExerciseItem(id: UUID(), prompt: "La terre commence à trembler fortement pendant que vous êtes dans votre cuisine en Californie.", options: [], correctAnswer: "Baissez-vous, abritez-vous sous une table solide et agrippez-vous (Drop, Cover, and Hold On). Éloignez-vous des fenêtres, des placards hauts et de la cuisinière.", explanation: "S'abriter sous un meuble solide protège des objets qui tombent, tandis que s'éloigner des fenêtres et des meubles hauts réduit le risque de blessure par chute d'objets."),
            ExerciseItem(id: UUID(), prompt: "Une alerte de canicule extrême est émise pour votre région en Californie, avec des températures dépassant 40 degrés Celsius.", options: [], correctAnswer: "Restez à l'intérieur dans un endroit climatisé. Buvez beaucoup d'eau, même si vous n'avez pas soif. Évitez les efforts physiques extérieurs et fermez vos rideaux.", explanation: "La chaleur extrême sollicite fortement le système cardiovasculaire, surtout chez les personnes âgées ; rester hydraté et au frais prévient les coups de chaleur."),
            ExerciseItem(id: UUID(), prompt: "Les autorités émettent une alerte de mauvaise qualité de l'air en raison de la fumée provenant d'un incendie de forêt à proximité.", options: [], correctAnswer: "Restez à l'intérieur. Fermez toutes les fenêtres et portes. Activez votre climatiseur en mode recirculation d'air ou utilisez un purificateur d'air portable.", explanation: "La fumée d'incendie contient des particules fines nocives pour les poumons ; garder l'air extérieur hors de la maison limite l'exposition respiratoire."),
            ExerciseItem(id: UUID(), prompt: "Une panne de courant générale survient dans votre quartier en pleine nuit.", options: [], correctAnswer: "Utilisez une lampe de poche plutôt qu'une bougie pour éviter les risques d'incendie. Débranchez les appareils électroniques sensibles pour éviter les surtensions au retour du courant.", explanation: "Une bougie peut facilement provoquer un incendie en cas de chute, alors qu'une lampe de poche n'a pas de flamme ; débrancher les appareils évite les dégâts liés aux surtensions au retour du courant."),
            ExerciseItem(id: UUID(), prompt: "Vous sentez une forte odeur de gaz naturel (similaire à des œufs pourris) dans votre cuisine.", options: [], correctAnswer: "Sortez immédiatement de la maison avec tous les occupants. Ne touchez à aucun interrupteur électrique et n'allumez rien. Appelez la compagnie de gaz ou le 911 depuis l'extérieur.", explanation: "Une odeur de gaz signale un risque d'explosion ; toute étincelle, y compris celle d'un interrupteur électrique, peut l'enflammer, d'où la nécessité de sortir sans rien allumer."),
            ExerciseItem(id: UUID(), prompt: "Vous remarquez de la moisissure noire qui se développe sur une large surface sous l'évier de la cuisine.", options: [], correctAnswer: "Ne touchez pas à la moisissure directement. Signalez-le immédiatement à votre propriétaire ou faites appel à un professionnel. Portez un masque si vous devez ouvrir le placard.", explanation: "La moisissure noire peut libérer des spores nocives pour les voies respiratoires en cas de manipulation directe, d'où l'importance de laisser un professionnel s'en occuper."),
            ExerciseItem(id: UUID(), prompt: "Vous constatez que l'eau du robinet de votre cuisine est de couleur marron après des travaux municipaux dans la rue.", options: [], correctAnswer: "Ne buvez pas cette eau et ne l'utilisez pas pour cuisiner. Laissez couler l'eau froide pendant quelques minutes pour voir si elle redevient claire. Si elle reste trouble, contactez le service des eaux.", explanation: "Une eau trouble après des travaux peut contenir des sédiments ou des contaminants ; laisser couler l'eau permet souvent d'évacuer les particules avant de la consommer à nouveau."),
            ExerciseItem(id: UUID(), prompt: "Une forte tempête hivernale est annoncée avec un risque d'inondation soudaine dans votre zone résidentielle.", options: [], correctAnswer: "Préparez un sac d'urgence avec vos médicaments et documents importants. Évitez de conduire dans les zones inondées. Suivez les consignes d'évacuation locales si nécessaire.", explanation: "Se préparer à l'avance avec les documents essentiels et éviter les routes inondées limite les risques, car une faible hauteur d'eau suffit à emporter un véhicule."),
            ExerciseItem(id: UUID(), prompt: "Vous perdez votre portefeuille contenant vos cartes de crédit et vos pièces d'identité dans un lieu public.", options: [], correctAnswer: "Contactez immédiatement vos banques pour faire opposition sur vos cartes de crédit. Déclarez la perte ou le vol au commissariat de police local pour vous protéger contre l'usurpation d'identité.", explanation: "Agir vite auprès des banques et de la police limite les dégâts financiers, car un voleur peut utiliser les cartes ou l'identité avant que l'opposition ne soit faite."),
            ExerciseItem(id: UUID(), prompt: "Vous devez évacuer votre domicile en urgence en raison d'un incendie de forêt et vous n'avez pas de réseau cellulaire sur votre téléphone.", options: [], correctAnswer: "Prenez votre sac d'urgence et quittez les lieux immédiatement en suivant les itinéraires d'évacuation officiels. N'attendez pas de recevoir un signal ou un appel de confirmation.", explanation: "En cas d'évacuation obligatoire, la priorité est de partir immédiatement selon l'itinéraire officiel, car attendre un signal téléphonique retarde inutilement la mise en sécurité."),
            ExerciseItem(id: UUID(), prompt: "Votre voiture tombe en panne avec un pneu plat au milieu de l'autoroute pendant les heures de pointe.", options: [], correctAnswer: "Essayez de vous ranger sur l'accotement droit. Restez à l'intérieur du véhicule avec votre ceinture attachée. Allumez vos feux de détresse et appelez l'assistance routière ou la police.", explanation: "Rester ceinturé à l'intérieur du véhicule protège des voitures qui circulent à grande vitesse à proximité, plutôt que de changer un pneu sur une autoroute dangereuse."),
            ExerciseItem(id: UUID(), prompt: "Vous mangez au restaurant et commencez soudainement à avoir du mal à respirer, avec des plaques rouges sur le visage.", options: [], correctAnswer: "Dites immédiatement aux personnes autour de vous que vous faites une réaction allergique. Utilisez votre auto-injecteur d'épinéphrine (EpiPen) si vous en avez un, et faites appeler le 911.", explanation: "Une difficulté respiratoire soudaine avec éruption cutanée après un repas signale une anaphylaxie, une urgence où l'épinéphrine agit en quelques minutes pour contrer la réaction."),
            ExerciseItem(id: UUID(), prompt: "Vous recevez une décharge électrique en branchant un vieil appareil ménager.", options: [], correctAnswer: "Débranchez l'appareil immédiatement si cela peut être fait sans danger (ou coupez le disjoncteur). N'utilisez plus cet appareil et faites-le inspecter ou jetez-le.", explanation: "Un vieil appareil provoquant une décharge électrique présente un défaut d'isolation dangereux ; le débrancher évite tout nouveau contact accidentel avec le courant."),
            ExerciseItem(id: UUID(), prompt: "Votre chien mange accidentellement une tablette entière de chocolat noir laissée sur la table basse.", options: [], correctAnswer: "Le chocolat noir est hautement toxique pour les chiens. Contactez immédiatement votre vétérinaire ou une clinique vétérinaire d'urgence pour faire vomir l'animal au plus vite.", explanation: "La théobromine contenue dans le chocolat noir est toxique pour les chiens et peut affecter le cœur et le système nerveux, d'où l'urgence d'une intervention vétérinaire."),
            ExerciseItem(id: UUID(), prompt: "Vous constatez que plusieurs colis livrés devant votre porte ont été volés ou ouverts.", options: [], correctAnswer: "Signalez le vol au transporteur et au vendeur pour demander un remboursement ou un remplacement. Déposez une plainte en ligne auprès du service de police locale.", explanation: "Signaler rapidement au transporteur et à la police crée une trace officielle nécessaire pour obtenir un remboursement et pour dissuader le vol de colis dans le quartier."),
            ExerciseItem(id: UUID(), prompt: "Vous commencez à avoir des maux de tête intenses après avoir utilisé des produits de nettoyage chimiques très forts dans une petite salle de bains sans fenêtre.", options: [], correctAnswer: "Quittez la pièce immédiatement pour aller respirer de l'air frais à l'extérieur. Ouvrez les fenêtres de la maison pour aérer et buvez un verre d'eau.", explanation: "Les vapeurs de produits chimiques concentrés dans un espace fermé peuvent provoquer une intoxication respiratoire ; l'air frais dilue rapidement les vapeurs inhalées."),
            ExerciseItem(id: UUID(), prompt: "La serrure de votre porte d'entrée est bloquée et vous êtes coincé dehors à la nuit tombée.", options: [], correctAnswer: "Appelez un serrurier professionnel agréé. N'essayez pas de forcer une fenêtre ou de casser la porte, car vous risqueriez de vous blesser ou d'être confondu avec un cambrioleur.", explanation: "Forcer une porte ou une fenêtre soi-même risque de causer des blessures ou d'alerter des voisins qui pourraient croire à un cambriolage, alors qu'un serrurier agréé intervient sans dommage."),
            ExerciseItem(id: UUID(), prompt: "Vous vous faites piquer par une guêpe et remarquez un gonflement rapide autour de la piqûre, accompagné de vertiges.", options: [], correctAnswer: "Il peut s'agir d'une réaction allergique sévère. Appelez le 911 immédiatement. Si vous disposez d'un kit d'urgence pour allergie, utilisez-le sans tarder.", explanation: "Un gonflement rapide accompagné de vertiges après une piqûre peut indiquer une anaphylaxie, une réaction potentiellement mortelle nécessitant une intervention médicale immédiate."),
            ExerciseItem(id: UUID(), prompt: "Vous remarquez des transactions suspectes et non autorisées sur votre relevé de carte de crédit en ligne.", options: [], correctAnswer: "Appelez le numéro d'urgence au dos de votre carte de crédit. Faites bloquer la carte actuelle, contestez les transactions frauduleuses et demandez l'envoi d'une nouvelle carte.", explanation: "Bloquer la carte compromise empêche toute nouvelle transaction frauduleuse, et contester rapidement les charges permet généralement un remboursement complet selon les protections bancaires."),
            ExerciseItem(id: UUID(), prompt: "Vous conduisez et votre voiture commence à faire de l'aquaplaning sur une route très mouillée après une forte pluie.", options: [], correctAnswer: "Ne freinez pas brusquement et n'accélérez pas. Retirez doucement votre pied de l'accélérateur et tenez fermement le volant en gardant les roues droites jusqu'à ce que vous repreniez de l'adhérence.", explanation: "Freiner brusquement pendant un aquaplaning bloque les roues et fait perdre le contrôle du véhicule, tandis que relâcher doucement l'accélérateur permet aux pneus de retrouver l'adhérence."),
            ExerciseItem(id: UUID(), prompt: "Vous glissez et tombez sur un sol mouillé dans un magasin d'alimentation, sans panneau d'avertissement visible.", options: [], correctAnswer: "Prenez des photos de l'endroit, signalez l'incident au responsable du magasin pour qu'il rédige un rapport d'accident, et consultez un médecin pour documenter vos blessures.", explanation: "Documenter la scène et obtenir un rapport officiel protège les droits de la victime en cas de réclamation ultérieure pour blessure liée à la négligence du magasin."),
            ExerciseItem(id: UUID(), prompt: "Vous constatez que la date d'expiration inscrite sur votre extincteur domestique est dépassée depuis deux ans.", options: [], correctAnswer: "Remplacez l'extincteur par un modèle neuf ou faites-le recharger par un professionnel certifié. Un extincteur périmé risque de ne pas fonctionner en cas d'incendie.", explanation: "Un extincteur périmé peut avoir perdu de la pression ou de l'efficacité chimique, ce qui le rend peu fiable au moment critique d'un incendie."),
            ExerciseItem(id: UUID(), prompt: "Vous vous perdez sur un sentier de randonnée en fin d'après-midi et la température commence à chuter rapidement.", options: [], correctAnswer: "Restez sur le sentier balisé. Essayez d'appeler les secours avec votre téléphone. Si vous n'avez pas de réseau, trouvez un abri contre le vent et utilisez des vêtements supplémentaires pour rester au chaud.", explanation: "Rester sur un sentier balisé facilite le repérage par les secours, et s'abriter du vent limite la perte de chaleur corporelle en cas d'hypothermie."),
            ExerciseItem(id: UUID(), prompt: "Vous recevez une pièce jointe étrange d'un ami sur Facebook Messenger, avec un message très court vous incitant à cliquer.", options: [], correctAnswer: "Ne cliquez pas sur le lien. Le compte de votre ami a probablement été piraté. Contactez-le par un autre moyen pour l'informer de la situation.", explanation: "Un lien envoyé de façon inhabituelle par un contact peut provenir d'un compte piraté utilisé pour diffuser des logiciels malveillants à l'insu du véritable propriétaire."),
            ExerciseItem(id: UUID(), prompt: "Le voyant de température de votre voiture s'allume en rouge et de la fumée blanche s'échappe du capot.", options: [], correctAnswer: "Arrêtez-vous en toute sécurité sur le côté de la route. Éteignez le moteur immédiatement. N'ouvrez pas le capot tout de suite pour éviter les brûlures graves dues à la vapeur.", explanation: "Une surchauffe moteur avec fumée signale un risque d'incendie ou de brûlure par la vapeur sous pression si le capot est ouvert trop tôt."),
            ExerciseItem(id: UUID(), prompt: "L'alarme de sécurité de votre maison se déclenche soudainement en pleine nuit sans raison apparente.", options: [], correctAnswer: "Restez dans votre chambre, verrouillez la porte et armez-vous de votre téléphone. Vérifiez les caméras de sécurité si vous en avez, ou attendez l'appel de la société de télésurveillance ou composez le 911.", explanation: "Rester en sécurité derrière une porte verrouillée en attendant confirmation évite un contact direct avec un possible intrus tout en laissant le temps aux secours d'intervenir."),
            ExerciseItem(id: UUID(), prompt: "Vous remarquez de la fumée épaisse s'échapper des fenêtres de la maison de votre voisin immédiat.", options: [], correctAnswer: "Appelez immédiatement le 911 pour signaler l'incendie. Ne tentez pas d'entrer dans la maison vous-même. Éloignez-vous de la zone pour laisser la place aux pompiers.", explanation: "Une fumée épaisse indique un incendie actif dangereux ; seuls des pompiers équipés peuvent intervenir sans risquer une intoxication ou un effondrement."),
            ExerciseItem(id: UUID(), prompt: "Vous cassez un bocal en verre sur le sol de la cuisine et de nombreux petits éclats se dispersent partout.", options: [], correctAnswer: "Ramassez les gros morceaux avec un balai ou des gants épais. Utilisez une serviette en papier humide ou un morceau de pain de mie pour récupérer les micro-éclats invisibles. Passez l'aspirateur.", explanation: "Les micro-éclats de verre sont souvent invisibles à l'œil nu et peuvent blesser les pieds ; un matériau collant comme le pain ou un chiffon humide permet de les capturer efficacement."),
            ExerciseItem(id: UUID(), prompt: "Un vent violent fait tomber un grand arbre qui arrache des lignes électriques dans votre rue.", options: [], correctAnswer: "Restez à l'intérieur. Si vous êtes dehors, éloignez-vous d'au moins 10 mètres des câbles tombés au sol, car ils peuvent être encore sous tension. Appelez le 911.", explanation: "Un câble électrique tombé au sol peut rester sous tension même après la chute de l'arbre, représentant un risque d'électrocution mortelle à distance."),
            ExerciseItem(id: UUID(), prompt: "Vous trouvez une seringue usagée jetée sur le bord du trottoir près de votre boîte aux lettres.", options: [], correctAnswer: "Ne la ramassez pas à mains nues. Utilisez des pinces pour la placer dans un récipient rigide en plastique si vous devez la déplacer, ou signalez-la aux services de nettoyage municipaux.", explanation: "Une seringue usagée peut transmettre des maladies par piqûre accidentelle ; la manipuler avec un outil plutôt qu'à mains nues élimine ce risque de contamination.")
        ]
    )
    
