            ExerciseItem(id: UUID(), prompt: "Café moulu : Option A) Une boîte de 12 onces pour 8,99 $ (0,75 $ l'once) ou Option B) Une boîte de 33 onces pour 14,99 $ (0,45 $ l'once) ?", options: ["Option A — Boîte de 12 oz pour 8,99 $", "Option B — Boîte de 33 oz pour 14,99 $"], correctAnswer: "Option B — Boîte de 33 oz pour 14,99 $", explanation: "Le format économique de 33 onces permet de réaliser une économie importante au poids."),
            ExerciseItem(id: UUID(), prompt: "Liquide vaisselle : Option A) Marque nationale de 20 onces pour 4,00 $ (0,20 $ l'once) ou Option B) Marque de distributeur de 28 onces pour 2,50 $ (0,089 $ l'once) ?", options: ["Option A — Marque nationale de 20 oz à 4,00 $", "Option B — Marque distributeur de 28 oz à 2,50 $"], correctAnswer: "Option B — Marque distributeur de 28 oz à 2,50 $", explanation: "La marque distributeur offre plus de produit pour un coût inférieur."),
            ExerciseItem(id: UUID(), prompt: "Riz blanc : Option A) Sac de 5 livres pour 4,00 $ (0,80 $ la livre) ou Option B) Sac de 20 livres pour 12,00 $ (0,60 $ la livre) ?", options: ["Option A — Sac de 5 livres pour 4,00 $", "Option B — Sac de 20 livres pour 12,00 $"], correctAnswer: "Option B — Sac de 20 livres pour 12,00 $", explanation: "Le sac de 20 livres est plus économique à la livre."),
            ExerciseItem(id: UUID(), prompt: "Farine : Option A) Sac de 2 livres pour 1,80 $ (0,90 $ la livre) ou Option B) Sac de 5 livres pour 3,50 $ (0,70 $ la livre) ?", options: ["Option A — Sac de 2 livres pour 1,80 $", "Option B — Sac de 5 livres pour 3,50 $"], correctAnswer: "Option B — Sac de 5 livres pour 3,50 $", explanation: "Le paquet de 5 livres a un meilleur rapport qualité-prix à la livre."),
            ExerciseItem(id: UUID(), prompt: "Thon en boîte : Option A) Une boîte individuelle de 5 onces pour 1,50 $ (0,30 $ l'once) ou Option B) Un lot de 4 boîtes de 5 onces pour 5,00 $ (0,25 $ l'once) ?", options: ["Option A — Boîte individuelle pour 1,50 $", "Option B — Lot de 4 boîtes pour 5,00 $"], correctAnswer: "Option B — Lot de 4 boîtes pour 5,00 $", explanation: "L'achat en lot réduit le coût unitaire de chaque boîte."),
            ExerciseItem(id: UUID(), prompt: "Huile d'olive : Option A) Une bouteille de 17 onces pour 7,00 $ (0,41 $ l'once) ou Option B) Une bouteille de 34 onces pour 12,00 $ (0,35 $ l'once) ?", options: ["Option A — Bouteille de 17 oz pour 7,00 $", "Option B — Bouteille de 34 oz pour 12,00 $"], correctAnswer: "Option B — Bouteille de 34 oz pour 12,00 $", explanation: "La bouteille de 34 onces offre un coût par once inférieur."),
            ExerciseItem(id: UUID(), prompt: "Sucre : Option A) Sac de 4 livres pour 3,20 $ (0,80 $ la livre) ou Option B) Sac de 10 livres pour 6,50 $ (0,65 $ la livre) ?", options: ["Option A — Sac de 4 livres pour 3,20 $", "Option B — Sac de 10 livres pour 6,50 $"], correctAnswer: "Option B — Sac de 10 livres pour 6,50 $", explanation: "Le prix au poids de 0,65 $ la livre pour le sac de 10 livres est inférieur à 0,80 $ la livre pour le sac de 4 livres, ce qui en fait le meilleur rapport qualité-prix."),
            ExerciseItem(id: UUID(), prompt: "Lessive liquide : Option A) Bouteille de 50 onces pour 8,00 $ (0,16 $ l'once) ou Option B) Bouteille de 100 onces pour 13,00 $ (0,13 $ l'once) ?", options: ["Option A — Bouteille de 50 oz à 8,00 $", "Option B — Bouteille de 100 oz à 13,00 $"], correctAnswer: "Option B — Bouteille de 100 oz à 13,00 $", explanation: "À 0,13 $ l'once, la bouteille de 100 onces revient moins cher à l'unité que la bouteille de 50 onces à 0,16 $ l'once."),
            ExerciseItem(id: UUID(), prompt: "Flocons d'avoine : Option A) Boîte de 18 onces pour 3,00 $ (0,166 $ l'once) ou Option B) Boîte de 42 onces pour 5,00 $ (0,119 $ l'once) ?", options: ["Option A — Boîte de 18 oz pour 3,00 $", "Option B — Boîte de 42 oz pour 5,00 $"], correctAnswer: "Option B — Boîte de 42 oz pour 5,00 $", explanation: "À 0,119 $ l'once contre 0,166 $ l'once, la boîte de 42 onces offre un meilleur prix unitaire malgré un prix total plus élevé."),
            ExerciseItem(id: UUID(), prompt: "Sel : Option A) Un pot de 26 onces pour 1,30 $ (0,05 $ l'once) ou Option B) Deux pots de 26 onces pour 2,00 $ (0,038 $ l'once) ?", options: ["Option A — Un pot de 26 oz pour 1,30 $", "Option B — Deux pots de 26 oz pour 2,00 $"], correctAnswer: "Option B — Deux pots de 26 oz pour 2,00 $", explanation: "Deux pots de 26 onces à 2,00 $ reviennent à 0,038 $ l'once, un prix unitaire inférieur au pot unique vendu à 0,05 $ l'once."),
            ExerciseItem(id: UUID(), prompt: "Bananes : Option A) Bananes biologiques à 0,99 $ la livre ou Option B) Bananes conventionnelles à 0,59 $ la livre ?", options: ["Option A — Bananes biologiques à 0,99 $", "Option B — Bananes conventionnelles à 0,59 $"], correctAnswer: "Option B — Bananes conventionnelles à 0,59 $", explanation: "Les bananes conventionnelles offrent un coût inférieur pour la même quantité de fruit."),
            ExerciseItem(id: UUID(), prompt: "Céréales : Option A) Une boîte de 12 onces pour 4,50 $ ou Option B) Un sac de 32 onces pour 6,00 $ ?", options: ["Option A — Boîte de 12 oz à 4,50 $", "Option B — Sac de 32 oz à 6,00 $"], correctAnswer: "Option B — Sac de 32 oz à 6,00 $", explanation: "L'achat en sac de grand format offre un coût nettement plus bas par once."),
            ExerciseItem(id: UUID(), prompt: "Fromage râpé : Option A) Un sachet de 8 onces pour 3,00 $ (0,375 $ l'once) ou Option B) Un sachet de 16 onces pour 5,00 $ (0,312 $ l'once) ?", options: ["Option A — Sachet de 8 oz pour 3,00 $", "Option B — Sachet de 16 oz pour 5,00 $"], correctAnswer: "Option B — Sachet de 16 oz pour 5,00 $", explanation: "Le sachet de 16 onces revient à 0,312 $ l'once, moins cher à l'unité que le sachet de 8 onces à 0,375 $ l'once."),
            ExerciseItem(id: UUID(), prompt: "Fraises : Option A) Barquette de 1 livre pour 2,99 $ ou Option B) Deux barquettes de 1 livre pour 5,00 $ ?", options: ["Option A — Une barquette pour 2,99 $", "Option B — Deux barquettes pour 5,00 $"], correctAnswer: "Option B — Deux barquettes pour 5,00 $", explanation: "Le prix unitaire passe à 2,50 $ la barquette dans le lot de deux."),
            ExerciseItem(id: UUID(), prompt: "Eau en bouteille : Option A) Une bouteille individuelle de 1 livre (ou 1 litre) pour 1,50 $ ou Option B) Un paquet de 24 bouteilles de 0,5 litre pour 4,00 $ ?", options: ["Option A — Bouteille individuelle à 1,50 $", "Option B — Paquet de 24 bouteilles pour 4,00 $"], correctAnswer: "Option B — Paquet de 24 bouteilles pour 4,00 $", explanation: "Le paquet contient 12 litres d'eau au total pour seulement 4,00 $."),
            ExerciseItem(id: UUID(), prompt: "Pommes de terre : Option A) Sac de 5 livres pour 3,50 $ (0,70 $ la livre) ou Option B) Sac de 10 livres pour 5,00 $ (0,50 $ la livre) ?", options: ["Option A — Sac de 5 livres pour 3,50 $", "Option B — Sac de 10 livres pour 5,00 $"], correctAnswer: "Option B — Sac de 10 livres pour 5,00 $", explanation: "Le sac de 10 livres à 0,50 $ la livre coûte moins cher à l'unité que le sac de 5 livres à 0,70 $ la livre."),
            ExerciseItem(id: UUID(), prompt: "Sacs poubelle : Option A) Une boîte de 30 sacs pour 6,00 $ (0,20 $ le sac) ou Option B) Une boîte de 80 sacs pour 12,00 $ (0,15 $ le sac) ?", options: ["Option A — Boîte de 30 sacs pour 6,00 $", "Option B — Boîte de 80 sacs pour 12,00 $"], correctAnswer: "Option B — Boîte de 80 sacs pour 12,00 $", explanation: "La boîte de 80 sacs revient à 0,15 $ le sac, un prix unitaire plus avantageux que la boîte de 30 sacs à 0,20 $ le sac.")
        ]
    )
    
    // MARK: - Exercise 4: Functional Writing
    private static let exercise4 = Exercise(
        id: UUID(),
        title: "Rédaction fonctionnelle",
        instructions: "Rédigez une réponse à chaque consigne. Appuyez sur \"Afficher la réponse\" pour voir un exemple de message modèle.",
        section: .functionalSkills,
        type: .openEnded,
        trackedType: nil,
        difficulty: .medium,
        items: [
            ExerciseItem(id: UUID(), prompt: "Écrivez un mot à votre gardienne d'animaux, Line, pour lui expliquer comment nourrir vos deux chats pendant votre absence de 4 jours.", options: [], correctAnswer: "Bonjour Line, merci de t'occuper de Félix et Minou. Donne-leur une demi-tasse de croquettes sèches matin et soir. De l'eau fraîche tous les jours. Minou a tendance à se cacher sous le lit mais sortira s'il a faim. Nettoie la litière une fois par jour. La nourriture est dans le placard de la cuisine. Appelle-moi s'il y a un problème. — [Votre Nom]", explanation: "Un mot efficace pour une gardienne doit indiquer clairement les quantités, la fréquence des repas et les habitudes particulières des animaux pour éviter toute erreur pendant l'absence."),
            ExerciseItem(id: UUID(), prompt: "Écrivez une note à votre propriétaire, M. Tremblay, pour signaler une fuite d'eau au plafond de votre salle de bains.", options: [], correctAnswer: "Cher M. Tremblay, je vous contacte pour signaler une fuite d'eau au plafond de ma salle de bains dans l'appartement 3C. L'eau semble provenir du logement du dessus et goutte depuis deux jours. Une tache d'humidité commence à se former. Merci de faire intervenir un plombier dès que possible. Vous pouvez me joindre au 555-456-7890. Cordialement, [Votre Nom]", explanation: "Signaler précisément l'emplacement et la durée d'une fuite permet au propriétaire d'agir rapidement avant que les dégâts des eaux ne s'aggravent."),
            ExerciseItem(id: UUID(), prompt: "Écrivez un court message poli pour refuser une invitation à dîner chez la famille Dubois en raison d'un engagement déjà prévu ce week-end-là.", options: [], correctAnswer: "Chère famille Dubois, merci beaucoup pour votre gentille invitation à dîner ce samedi. Malheureusement, j'ai déjà un engagement prévu de longue date ce week-end et je ne pourrai pas être des vôtres. J'espère que vous passerez une excellente soirée et j'espère vous revoir bientôt. Amicalement, [Votre Nom]", explanation: "Un refus poli qui explique brièvement la raison, sans en faire trop, maintient une relation cordiale tout en étant honnête sur l'indisponibilité."),
            ExerciseItem(id: UUID(), prompt: "Écrivez une demande de congés à votre superviseur, M. Roy, pour demander des vacances du 28 juillet au 8 août.", options: [], correctAnswer: "Monsieur Roy, je souhaite solliciter des congés du lundi 28 juillet au vendredi 8 août. Je veillerai à ce que tous mes dossiers soient à jour avant mon départ et j'organiserai un suivi avec mes collègues si nécessaire. Je reste à votre disposition pour en discuter. Cordialement, [Votre Nom]", explanation: "Préciser les dates exactes et rassurer sur la continuité du travail facilite l'approbation d'une demande de congé par un supérieur."),
            ExerciseItem(id: UUID(), prompt: "Écrivez un court SMS à un ami pour annuler vos plans de demain car vous ne vous sentez pas très bien.", options: [], correctAnswer: "Salut ! Je suis vraiment désolé mais je vais devoir annuler notre rencontre de demain. Je ne me sens pas très bien aujourd'hui et je préfère ne rien te transmettre. On reporte ça dès que je vais mieux ? Désolé pour le contretemps !", explanation: "Un message court, honnête sur le motif et proposant un report montre du respect pour l'ami tout en gérant l'imprévu de santé."),
            ExerciseItem(id: UUID(), prompt: "Écrivez un mot court à laisser sur la table de la cuisine pour expliquer à un membre de votre famille où vous êtes allé et quand vous rentrerez.", options: [], correctAnswer: "Je suis parti faire quelques courses à l'épicerie et chercher mes médicaments à la pharmacie. Je devrais être de retour pour 14h00. Il y a de la soupe au réfrigérateur si tu as faim. À tout de suite !", explanation: "Indiquer la destination, l'heure de retour prévue et une information pratique (comme la présence de nourriture) rassure la personne qui trouve le mot."),
            ExerciseItem(id: UUID(), prompt: "Écrivez une lettre de réclamation courte à une entreprise à propos d'un colis reçu endommagé.", options: [], correctAnswer: "Madame, Monsieur, je vous écris concernant ma commande reçue ce jour. L'article est arrivé brisé avec le couvercle fêlé en raison d'un emballage insuffisant. Je sollicite l'envoi d'un produit de remplacement ou un remboursement complet. Merci de me contacter à [votre courriel ou téléphone] pour régler ce problème. Cordialement, [Votre Nom]", explanation: "Décrire précisément le problème et formuler clairement la demande (remboursement ou remplacement) augmente les chances d'une réponse rapide du service client."),
            ExerciseItem(id: UUID(), prompt: "Écrivez une liste de courses simple pour préparer des repas faciles pour deux personnes pendant une semaine avec un budget d'environ 60 $.", options: [], correctAnswer: "FRUITS ET LÉGUMES : Bananes, pommes, carottes, laitue, tomates, oignon. PRODUITS LAITIERS : Œufs, lait, fromage râpé. VIANDE : 2 lb de poitrines de poulet, 1 lb de bœuf haché. ÉPICERIE : Pâtes, sauce tomate, riz, pain de mie, beurre de cacahuète, soupe en conserve. Total estimé : entre 50 $ et 60 $ selon la marque et le magasin.", explanation: "Organiser la liste par catégorie alimentaire facilite les courses en magasin et aide à respecter le budget fixé en visualisant les postes de dépense."),
            ExerciseItem(id: UUID(), prompt: "Écrivez un mot de remerciement à votre voisin Luc pour avoir tondu votre pelouse pendant que vous étiez malade.", options: [], correctAnswer: "Bonjour Luc, un grand merci d'avoir tondu ma pelouse pendant que j'étais malade la semaine dernière. Ton aide généreuse m'a beaucoup soulagé et a rendu ma convalescence plus serene. N'hésite pas si je peux t'aider en retour. Amicalement, [Votre Nom]", explanation: "Exprimer une gratitude sincère et personnalisée pour un service rendu renforce la relation de bon voisinage."),
            ExerciseItem(id: UUID(), prompt: "Écrivez un courriel court à votre médecin pour demander le renouvellement de votre ordonnance habituelle.", options: [], correctAnswer: "Bonjour Docteur, je vous contacte pour solliciter le renouvellement de mon ordonnance pour le traitement de la tension. Ma pharmacie habituelle est celle de la rue Principale. Serait-il possible d'envoyer l'ordonnance directement à leur adresse électronique ? Merci beaucoup, [Votre Nom]", explanation: "Mentionner le nom du traitement et la pharmacie habituelle permet au médecin de traiter la demande de renouvellement rapidement sans confusion."),
            ExerciseItem(id: UUID(), prompt: "Écrivez un message à laisser sur le pare-brise d'une voiture garée devant votre garage qui bloque votre sortie.", options: [], correctAnswer: "Bonjour, votre véhicule bloque l'accès à mon garage et m'empêche de sortir pour aller travailler. Merci de déplacer votre voiture immédiatement. Si vous avez besoin de me joindre, je suis dans la maison d'en face ou au 555-890-1234. Merci de votre compréhension.", explanation: "Un message ferme mais poli, avec un moyen de contact, permet de résoudre la gêne sans provoquer de conflit inutile avec le voisin."),
            ExerciseItem(id: UUID(), prompt: "Écrivez un message d'anniversaire chaleureux pour les 70 ans de votre sœur Hélène.", options: [], correctAnswer: "Chère Hélène, je te souhaite un merveilleux anniversaire pour tes 70 ans ! Que cette journée soit remplie de joie, de rires et entourée des personnes que tu aimes. Je suis très chanceux de t'avoir comme sœur. Gros bisous et à très bientôt pour fêter cela ensemble !", explanation: "Un message chaleureux et personnel souligne l'importance de l'occasion et exprime des sentiments sincères envers un proche."),
            ExerciseItem(id: UUID(), prompt: "Écrivez un court mot à poster sur le groupe de discussion de votre quartier pour signaler que vous avez trouvé des clés perdues dans le parc de la ville.", options: [], correctAnswer: "Bonjour à tous, j'ai trouvé un trousseau de clés près des balançoires du parc ce matin vers 10h00. Il y a trois clés et un porte-clés bleu. Si ce sont les vôtres, merci de me contacter par message privé pour que je puisse vous les rendre.", explanation: "Décrire précisément l'objet trouvé, le lieu et l'heure permet au propriétaire légitime de le reconnaître sans que d'autres personnes ne puissent le réclamer à tort."),
            ExerciseItem(id: UUID(), prompt: "Écrivez une note de rappel à vous-même pour la journée de demain avec trois tâches importantes à accomplir.", options: [], correctAnswer: "RAPPEL POUR DEMAIN : 1. Prendre rendez-vous chez le dentiste à 9h00. 2. Aller chercher les médicaments à la pharmacie avant midi. 3. Arroser les plantes du jardin en fin de journée.", explanation: "Une liste numérotée avec des horaires précis aide à organiser sa journée et à ne rien oublier parmi les tâches importantes."),
            ExerciseItem(id: UUID(), prompt: "Écrivez un courriel court au service d'assistance de votre fournisseur d'accès internet pour signaler une panne de connexion depuis ce matin.", options: [], correctAnswer: "Madame, Monsieur, je vous contacte car je n'ai plus de connexion internet à mon domicile depuis ce matin 8h00. Le voyant de ma box reste rouge malgré plusieurs redémarrages. Mon numéro de compte client est le 987654. Merci de m'aider à résoudre ce problème rapidement. Cordialement, [Votre Nom]", explanation: "Fournir l'heure du problème, les symptômes techniques observés et le numéro de compte permet au support technique de diagnostiquer rapidement la panne."),
            ExerciseItem(id: UUID(), prompt: "Écrivez un mot à votre coiffeuse habituelle, Sophie, pour lui demander si elle a des disponibilités vendredi prochain après-midi pour une coupe de cheveux.", options: [], correctAnswer: "Bonjour Sophie, j'aimerais savoir si vous auriez une disponibilité vendredi prochain dans l'après-midi, idéalement vers 14h00 ou 15h00, pour une coupe de cheveux. Merci de me confirmer si cela est possible. Bonne journée et à bientôt, [Votre Nom]", explanation: "Proposer des créneaux horaires précis facilite la réponse rapide de la coiffeuse pour confirmer ou ajuster le rendez-vous."),
            ExerciseItem(id: UUID(), prompt: "Écrivez un mot d'excuse à votre professeur d'art pour justifier votre absence au cours d'hier soir.", options: [], correctAnswer: "Chère Madame, je vous prie de bien vouloir m'excuser pour mon absence au cours d'art d'hier soir. J'ai eu un imprévu médical de dernière minute. Je ferai en sorte de rattraper le travail pour le prochain cours. Merci de votre compréhension, [Votre Nom]", explanation: "Une explication brève du motif d'absence et un engagement à rattraper le travail montrent du respect envers l'enseignant."),
            ExerciseItem(id: UUID(), prompt: "Écrivez un message de félicitations à votre voisin dont la fille vient de se marier.", options: [], correctAnswer: "Cher voisin, toutes mes félicitations pour le mariage de votre fille. Les photos étaient magnifiques et elle semblait tellement heureuse. Je vous souhaite beaucoup de bonheur en famille pour cette nouvelle étape de vie. Amicalement, [Votre Nom]", explanation: "Un message de félicitations personnel qui mentionne un détail précis de l'événement rend le compliment plus sincère et chaleureux.")
        ]
    )
    
    // MARK: - Exercise 5: Cooking Steps
    private static let exercise5 = Exercise(
        id: UUID(),
        title: "Étapes de cuisine",
        instructions: "Les étapes ci-dessous sont dans le MAUVAIS ordre. Remettez-les dans l'ordre chronologique correct.",
        section: .functionalSkills,
        type: .sequencing,
        trackedType: .sequencing,
        difficulty: .medium,
        items: [
            ExerciseItem(id: UUID(), prompt: "Œufs brouillés", options: ["Battre les œufs avec une fourchette", "Retirer du feu dès qu'ils sont pris", "Chauffer la poêle à feu moyen-doux et ajouter le beurre", "Casser les œufs dans un bol", "Verser le mélange d'œufs dans la poêle", "Ajouter du sel et un filet de lait", "Servir immédiatement"], correctAnswer: "Casser les œufs dans un bol | Ajouter du sel et un filet de lait | Battre les œufs avec une fourchette | Chauffer la poêle à feu moyen-doux et ajouter le beurre | Verser le mélange d'œufs dans la poêle | Retirer du feu dès qu'ils sont pris | Servir immédiatement", explanation: "Battre les œufs avant cuisson permet d'homogénéiser le blanc et le jaune, et retirer du feu dès qu'ils sont pris évite qu'ils ne deviennent secs ou caoutchouteux."),
            ExerciseItem(id: UUID(), prompt: "Boîte de soupe condensée", options: ["Chauffer à feu moyen en remuant de temps en temps", "Ouvrir la boîte de conserve", "Verser dans un bol et servir", "Verser la soupe dans une casserole", "Ajouter une boîte d'eau et remuer"], correctAnswer: "Ouvrir la boîte de conserve | Verser la soupe dans une casserole | Ajouter une boîte d'eau et remuer | Chauffer à feu moyen en remuant de temps en temps | Verser dans un bol et servir", explanation: "Diluer la soupe condensée avec de l'eau avant de la chauffer est nécessaire car elle est concentrée et immangeable telle quelle."),
            ExerciseItem(id: UUID(), prompt: "Sandwich au fromage grillé (Grilled Cheese)", options: ["Retourner le sandwich", "Cuire jusqu'à ce que le dessous soit doré", "Placer la deuxième tranche de pain dessus face beurrée vers le haut", "Placer une tranche de pain face beurrée vers le bas dans une poêle froide", "Beurrer un côté de chaque tranche de pain", "Cuire jusqu'à ce que le deuxième côté soit doré et le fromage fondu", "Ajouter le fromage sur le dessus", "Retirer et servir"], correctAnswer: "Beurrer un côté de chaque tranche de pain | Placer une tranche de pain face beurrée vers le bas dans une poêle froide | Ajouter le fromage sur le dessus | Placer la deuxième tranche de pain dessus face beurrée vers le haut | Cuire jusqu'à ce que le dessous soit doré | Retourner le sandwich | Cuire jusqu'à ce que le deuxième côté soit doré et le fromage fondu | Retirer et servir", explanation: "Beurrer le pain avant cuisson et cuire dans une poêle froide permettent une dorure progressive et uniforme sans brûler l'extérieur avant que le fromage ne fonde."),
            ExerciseItem(id: UUID(), prompt: "Œufs durs", options: ["Égoutter et transférer dans de l'eau glacée", "Porter à ébullition complète", "Couvrir la casserole et éteindre le feu", "Placer les œufs dans une casserole", "Écaler les œufs lorsqu'ils sont refroidis", "Couvrir d'eau froide à hauteur d'un pouce", "Laisser reposer pendant 10 à 12 minutes"], correctAnswer: "Placer les œufs dans une casserole | Couvrir d'eau froide à hauteur d'un pouce | Porter à ébullition complète | Couvrir la casserole et éteindre le feu | Laisser reposer pendant 10 à 12 minutes | Égoutter et transférer dans de l'eau glacée | Écaler les œufs lorsqu'ils sont refroidis", explanation: "Transférer les œufs dans l'eau glacée après cuisson arrête immédiatement la cuisson et facilite l'écalage en détachant la coquille du blanc."),
            ExerciseItem(id: UUID(), prompt: "Flocons d'avoine classiques (oatmeal)", options: ["Ajouter des garnitures comme de la banane ou du miel", "Réduire le feu et remuer pendant 5 minutes jusqu'à épaississement", "Porter l'eau ou le lait à ébullition", "Ajouter les flocons d'avoine", "Servir chaud dans un bol"], correctAnswer: "Porter l'eau ou le lait à ébullition | Ajouter les flocons d'avoine | Réduire le feu et remuer pendant 5 minutes jusqu'à épaississement | Ajouter des garnitures comme de la banane ou du miel | Servir chaud dans un bol", explanation: "Porter le liquide à ébullition avant d'ajouter les flocons permet une cuisson uniforme, tandis que réduire le feu ensuite évite que le mélange n'attache au fond."),
            ExerciseItem(id: UUID(), prompt: "Pâtes au fromage en boîte (Mac & Cheese)", options: ["Égoutter les pâtes", "Ajouter le beurre, le lait et le sachet de fromage en poudre", "Faire bouillir de l'eau", "Remuer jusqu'à consistance crémeuse et servir", "Ajouter les pâtes et cuire 8 à 9 minutes", "Remettre les pâtes égouttées dans la casserole"], correctAnswer: "Faire bouillir de l'eau | Ajouter les pâtes et cuire 8 à 9 minutes | Égoutter les pâtes | Remettre les pâtes égouttées dans la casserole | Ajouter le beurre, le lait et le sachet de fromage en poudre | Remuer jusqu'à consistance crémeuse et servir", explanation: "Cuire les pâtes avant d'ajouter le fromage en poudre et le lait respecte l'ordre nécessaire pour obtenir une texture crémeuse sans grumeaux."),
            ExerciseItem(id: UUID(), prompt: "Pizza surgelée", options: ["Laisser reposer 2 à 3 minutes avant de couper", "Préchauffer le four à la température indiquée sur la boîte", "Cuire au four pendant la durée indiquée", "Retirer tout l'emballage, y compris le carton", "Utiliser des maniques pour retirer la pizza du four", "Placer la pizza directement sur la grille ou sur une plaque"], correctAnswer: "Préchauffer le four à la température indiquée sur la boîte | Retirer tout l'emballage, y compris le carton | Placer la pizza directement sur la grille ou sur une plaque | Cuire au four pendant la durée indiquée | Utiliser des maniques pour retirer la pizza du four | Laisser reposer 2 à 3 minutes avant de couper", explanation: "Préchauffer le four avant d'enfourner garantit une cuisson uniforme dès le début, et retirer l'emballage carton évite un risque d'incendie dans le four."),
            ExerciseItem(id: UUID(), prompt: "Riz blanc à la casserole", options: ["Égrener avec une fourchette et servir", "Porter à ébullition à feu moyen-vif", "Réduire le feu au minimum et couvrir hermétiquement", "Retirer du feu et laisser reposer à couvert pendant 5 minutes", "Mélanger 1 tasse de riz et 2 tasses d'eau dans une casserole", "Cuire à couvert pendant 18 minutes sans soulever le couvercle"], correctAnswer: "Mélanger 1 tasse de riz et 2 tasses d'eau dans une casserole | Porter à ébullition à feu moyen-vif | Réduire le feu au minimum et couvrir hermétiquement | Cuire à couvert pendant 18 minutes sans soulever le couvercle | Retirer du feu et laisser reposer à couvert pendant 5 minutes | Égrener avec une fourchette et servir", explanation: "Couvrir hermétiquement et réduire le feu permettent au riz d'absorber l'eau par la vapeur sans brûler, et le laisser reposer termine la cuisson uniformément."),
            ExerciseItem(id: UUID(), prompt: "Pancakes à partir d'une boîte de préparation", options: ["Retourner lorsque des bulles se forment à la surface", "Verser environ un quart de tasse de pâte par pancake", "Cuire jusqu'à ce que le deuxième côté soit doré", "Mélanger la poudre avec les œufs, le lait et l'huile comme indiqué", "Chauffer une poêle légèrement graissée à feu moyen", "Lire les instructions sur la boîte de préparation", "Ne pas trop mélanger la pâte, les grumeaux sont normaux"], correctAnswer: "Lire les instructions sur la boîte de préparation | Mélanger la poudre avec les œufs, le lait et l'huile comme indiqué | Ne pas trop mélanger la pâte, les grumeaux sont normaux | Chauffer une poêle légèrement graissée à feu moyen | Verser environ un quart de tasse de pâte par pancake | Retourner lorsque des bulles se forment à la surface | Cuire jusqu'à ce que le deuxième côté soit doré", explanation: "Lire les instructions avant de mélanger évite les erreurs de dosage, et ne pas trop mélanger la pâte préserve la texture moelleuse des pancakes."),
            ExerciseItem(id: UUID(), prompt: "Salade verte classique", options: ["Ajouter la vinaigrette juste avant de servir", "Mélanger délicatement et servir immédiatement", "Laver les feuilles de salade sous l'eau froide", "Ajouter les garnitures comme les tomates, concombres et croûtons", "Sécher les feuilles de salade avec une essoreuse ou du papier absorbant", "Déchirer les feuilles en morceaux faciles à manger"], correctAnswer: "Laver les feuilles de salade sous l'eau froide | Sécher les feuilles de salade avec une essoreuse ou du papier absorbant | Déchirer les feuilles en morceaux faciles à manger | Ajouter les garnitures comme les tomates, concombres et croûtons | Ajouter la vinaigrette juste avant de servir | Mélanger délicatement et servir immédiatement", explanation: "Laver et sécher la salade avant de la couper évite que l'eau ne dilue la vinaigrette, qui doit être ajoutée juste avant de servir pour que les feuilles restent croquantes."),
            ExerciseItem(id: UUID(), prompt: "Thé chaud à l'infuseur", options: ["Placer l'infuseur dans la tasse", "Verser l'eau chaude sur l'infuseur", "Faire chauffer de l'eau dans une bouilloire", "Remplir l'infuseur avec des feuilles de thé", "Laisser infuser pendant 3 à 5 minutes", "Retirer l'infuseur et laisser refroidir légèrement"], correctAnswer: "Faire chauffer de l'eau dans une bouilloire | Remplir l'infuseur avec des feuilles de thé | Placer l'infuseur dans la tasse | Verser l'eau chaude sur l'infuseur | Laisser infuser pendant 3 à 5 minutes | Retirer l'infuseur et laisser refroidir légèrement", explanation: "Faire chauffer l'eau avant d'infuser le thé permet une extraction correcte des arômes, et laisser infuser le temps recommandé évite un thé trop amer ou trop faible."),
            ExerciseItem(id: UUID(), prompt: "Café filtre classique", options: ["Placer le filtre en papier dans le panier de la cafetière", "Verser de l'eau froide dans le réservoir d'eau", "Mesurer le café moulu et le mettre dans le filtre", "Allumer la cafetière", "Attendre que tout le café soit passé", "Servir chaud dans une tasse"], correctAnswer: "Placer le filtre en papier dans le panier de la cafetière | Verser de l'eau froide dans le réservoir d'eau | Mesurer le café moulu et le mettre dans le filtre | Allumer la cafetière | Attendre que tout le café soit passé | Servir chaud dans une tasse", explanation: "Placer le filtre puis mesurer le café avant de lancer la cafetière suit l'ordre logique nécessaire pour que l'eau chaude traverse correctement le café moulu."),
            ExerciseItem(id: UUID(), prompt: "Purée de pommes de terre", options: ["Peler et couper les pommes de terre en morceaux", "Faire bouillir dans de l'eau salée pendant 20 minutes", "Égoutter complètement les pommes de terre", "Écraser les pommes de terre à l'aide d'un presse-purée", "Ajouter du beurre et du lait chaud", "Mélanger jusqu'à obtention d'une texture crémeuse"], correctAnswer: "Peler et couper les pommes de terre en morceaux | Faire bouillir dans de l'eau salée pendant 20 minutes | Égoutter complètement les pommes de terre | Écraser les pommes de terre à l'aide d'un presse-purée | Ajouter du beurre et du lait chaud | Mélanger jusqu'à obtention d'une texture crémeuse", explanation: "Faire bouillir les pommes de terre avant de les écraser est nécessaire pour les ramollir, et ajouter le lait chaud plutôt que froid préserve une texture lisse."),
            ExerciseItem(id: UUID(), prompt: "Vinaigrette maison", options: ["Mesurer le vinaigre et le verser dans un bol", "Ajouter la moutarde, le sel et le poivre", "Verser l'huile d'olive lentement tout en fouettant", "Mélanger énergiquement jusqu'à émulsion", "Goûter et ajuster l'assaisonnement"], correctAnswer: "Mesurer le vinaigre et le verser dans un bol | Ajouter la moutarde, le sel et le poivre | Verser l'huile d'olive lentement tout en fouettant | Mélanger énergiquement jusqu'à émulsion | Goûter et ajuster l'assaisonnement", explanation: "Incorporer l'huile progressivement en fouettant permet de créer une émulsion stable entre l'huile et le vinaigre, qui se sépareraient sinon."),
            ExerciseItem(id: UUID(), prompt: "Toast au beurre", options: ["Placer la tranche de pain dans le grille-pain", "Abaisser le levier pour démarrer la cuisson", "Attendre que la tranche de pain soit éjectée", "Retirer le toast chaud avec précaution", "Étaler le beurre sur le toast immédiatement pour qu'il fonde"], correctAnswer: "Placer la tranche de pain dans le grille-pain | Abaisser le levier pour démarrer la cuisson | Attendre que la tranche de pain soit éjectée | Retirer le toast chaud avec précaution | Étaler le beurre sur le toast immédiatement pour qu'il fonde", explanation: "Le pain doit d'abord griller avant que le beurre ne soit étalé, car la chaleur du toast permet au beurre de fondre uniformément."),
            ExerciseItem(id: UUID(), prompt: "Pâtes alimentaires à la sauce tomate", options: ["Faire bouillir de l'eau dans une grande casserole", "Ajouter les pâtes et du sel dans l'eau bouillante", "Cuire selon le temps indiqué sur le paquet", "Égoutter les pâtes", "Mélanger les pâtes chaudes avec la sauce tomate préalablement chauffée"], correctAnswer: "Faire bouillir de l'eau dans une grande casserole | Ajouter les pâtes et du sel dans l'eau bouillante | Cuire selon le temps indiqué sur le paquet | Égoutter les pâtes | Mélanger les pâtes chaudes avec la sauce tomate préalablement chauffée", explanation: "Faire bouillir l'eau et cuire les pâtes selon le temps indiqué avant de les égoutter garantit une cuisson correcte avant l'ajout de la sauce chaude."),
            ExerciseItem(id: UUID(), prompt: "Salade de fruits frais", options: ["Laver tous les fruits", "Peler les fruits si nécessaire", "Couper les fruits en morceaux de taille égale", "Placer les morceaux dans un grand saladier", "Ajouter un filet de jus de citron pour éviter qu'ils ne brunissent", "Mélanger délicatement et réserver au frais"], correctAnswer: "Laver tous les fruits | Peler les fruits si nécessaire | Couper les fruits en morceaux de taille égale | Placer les morceaux dans un grand saladier | Ajouter un filet de jus de citron pour éviter qu'ils ne brunissent | Mélanger délicatement et réserver au frais", explanation: "Ajouter du jus de citron après la découpe empêche l'oxydation qui brunit rapidement certains fruits une fois exposés à l'air."),
            ExerciseItem(id: UUID(), prompt: "Poitrines de poulet au four", options: ["Préchauffer le four à 400 degrés Fahrenheit", "Placer le poulet dans un plat allant au four", "Assaisonner avec du sel, du poivre et de l'huile", "Cuire au four pendant 25 minutes", "Vérifier que le poulet n'est plus rose à cœur"], correctAnswer: "Préchauffer le four à 400 degrés Fahrenheit | Placer le poulet dans un plat allant au four | Assaisonner avec du sel, du poivre et de l'huile | Cuire au four pendant 25 minutes | Vérifier que le poulet n'est plus rose à cœur", explanation: "Préchauffer le four avant d'enfourner le poulet assure une cuisson homogène, et vérifier l'absence de couleur rose garantit que la viande est cuite à cœur en toute sécurité."),
            ExerciseItem(id: UUID(), prompt: "Guacamole simple", options: ["Couper l'avocat en deux et retirer le noyau", "Récupérer la chair de l'avocat avec une cuillère", "Écraser la chair à la fourchette dans un bol", "Ajouter du jus de citron vert et du sel", "Ajouter des tomates et oignons coupés finement", "Mélanger et servir avec des frites de tortilla"], correctAnswer: "Couper l'avocat en deux et retirer le noyau | Récupérer la chair de l'avocat avec une cuillère | Écraser la chair à la fourchette dans un bol | Ajouter du jus de citron vert et du sel | Ajouter des tomates et oignons coupés finement | Mélanger et servir avec des frites de tortilla", explanation: "Couper l'avocat et écraser sa chair avant d'ajouter les autres ingrédients permet d'obtenir une base homogène avant d'incorporer la texture des légumes coupés."),
            ExerciseItem(id: UUID(), prompt: "Légumes rôtis au four", options: ["Laver et découper les légumes de votre choix", "Disposer les légumes sur une plaque de cuisson", "Arroser d'huile d'olive et ajouter des herbes de Provence", "Enfourner dans un four préchauffé à 400 degrés Fahrenheit", "Faire rôtir pendant 30 minutes en remuant à mi-cuisson"], correctAnswer: "Laver et découper les légumes de votre choix | Disposer les légumes sur une plaque de cuisson | Arroser d'huile d'olive et ajouter des herbes de Provence | Enfourner dans un four préchauffé à 400 degrés Fahrenheit | Faire rôtir pendant 30 minutes en remuant à mi-cuisson", explanation: "Arroser d'huile avant l'enfournement permet aux légumes de dorer uniformément, et remuer à mi-cuisson évite qu'un côté ne brûle pendant que l'autre reste cru."),
            ExerciseItem(id: UUID(), prompt: "Soupe de légumes maison", options: ["Laver et éplucher les carottes, pommes de terre et poireaux", "Couper tous les légumes en dés", "Faire revenir les oignons dans un peu d'huile", "Ajouter les légumes coupés et couvrir de bouillon de légumes", "Laisser mijoter à feu moyen pendant 40 minutes", "Mixer la préparation pour obtenir un velouté"], correctAnswer: "Laver et éplucher les carottes, pommes de terre et poireaux | Couper tous les légumes en dés | Faire revenir les oignons dans un peu d'huile | Ajouter les légumes coupés et couvrir de bouillon de légumes | Laisser mijoter à feu moyen pendant 40 minutes | Mixer la préparation pour obtenir un velouté", explanation: "Faire revenir les oignons avant d'ajouter les autres légumes et le bouillon développe les arômes de base avant la cuisson longue qui attendrit l'ensemble."),
            ExerciseItem(id: UUID(), prompt: "Compote de pommes maison", options: ["Éplucher les pommes et retirer le trognon", "Couper les pommes en petits morceaux", "Placer les morceaux dans une casserole avec un peu d'eau et de cannelle", "Couvrir et cuire à feu doux pendant 20 minutes", "Écraser les pommes cuites à la fourchette ou au mixeur"], correctAnswer: "Éplucher les pommes et retirer le trognon | Couper les pommes en petits morceaux | Placer les morceaux dans une casserole avec un peu d'eau et de cannelle | Couvrir et cuire à feu doux pendant 20 minutes | Écraser les pommes cuites à la fourchette ou au mixeur", explanation: "Cuire les pommes à feu doux avant de les écraser permet de les ramollir suffisamment pour obtenir une texture de compote homogène.")
        ]
    )
    
    // MARK: - Exercise 6: Daily Life Skills
    private static let exercise6 = Exercise(
        id: UUID(),
        title: "Compétences de la vie quotidienne",
        instructions: "Pour chaque tâche, décrivez : le matériel nécessaire, les étapes clés et les risques potentiels. Appuyez sur \"Afficher la réponse\" pour voir la réponse modèle.",
        section: .functionalSkills,
        type: .openEnded,
        trackedType: nil,
        difficulty: .medium,
        items: [
            ExerciseItem(id: UUID(), prompt: "Comment faire une lessive ?", options: [], correctAnswer: "Matériel : vêtements sales, lessive, adoucissant. Étapes : Trier le linge par couleur et type de tissu. Vérifier les poches. Ajouter la bonne dose de lessive. Choisir la température de l'eau. Transférer dans le sèche-linge dès que c'est fini. Plier rapidement. Risques : mélanger du blanc et du rouge, surcharger la machine.", explanation: "Trier le linge par couleur avant lavage évite que les couleurs ne déteignent sur les vêtements clairs, un risque courant en cas de mélange."),
            ExerciseItem(id: UUID(), prompt: "Comment prendre un rendez-vous chez le médecin ?", options: [], correctAnswer: "Matériel : téléphone, carte d'assurance (Medi-Cal/Medicare), liste des symptômes, calendrier. Étapes : Appeler pendant les heures d'ouverture. Donner son nom, sa date de naissance et son numéro d'assurance. Expliquer le motif de la visite. Noter la date, l'heure et l'adresse. Risques : oublier de noter le rendez-vous, ne pas avoir sa carte d'assurance sous la main.", explanation: "Avoir sa carte d'assurance et ses informations personnelles prêtes avant l'appel accélère la prise de rendez-vous et évite les erreurs administratives."),
            ExerciseItem(id: UUID(), prompt: "Comment envoyer un courriel ?", options: [], correctAnswer: "Matériel : ordinateur ou smartphone, adresse électronique du destinataire. Étapes : Ouvrir l'application de messagerie. Cliquer sur Rédiger. Saisir l'adresse du destinataire. Écrire un objet clair. Rédiger le message. Se relire. Cliquer sur Envoyer. Risques : cliquer sur 'Répondre à tous' par erreur, oublier de joindre un fichier mentionné.", explanation: "Se relire avant d'envoyer un courriel permet de repérer les erreurs et de vérifier que le bon destinataire et les pièces jointes sont bien inclus."),
            ExerciseItem(id: UUID(), prompt: "Comment lire correctement une étiquette de médicament ?", options: [], correctAnswer: "Trouver : le nom du médicament, la dose prescrite, la fréquence de prise quotidienne, les consignes spéciales (par exemple, prendre pendant le repas), la date de péremption. Lire les étiquettes de mise en garde. Risques : confondre milligrammes et millilitres, ignorer l'avertissement de somnolence.", explanation: "Vérifier la dose exacte et la fréquence sur l'étiquette évite les erreurs de dosage potentiellement dangereuses, notamment la confusion entre milligrammes et millilitres."),
            ExerciseItem(id: UUID(), prompt: "Comment utiliser un distributeur automatique de billets (DAB) en toute sécurité ?", options: [], correctAnswer: "Matériel : carte bancaire, code PIN. Étapes : Choisir un guichet bien éclairé. Masquer le clavier avec sa main lors de la saisie du code. Récupérer sa carte et son reçu avant de s'éloigner. Ne jamais partager son code PIN. Risques : oublier sa carte dans le lecteur, utiliser un guichet isolé la nuit.", explanation: "Masquer le clavier lors de la saisie du code PIN empêche les regards indiscrets ou les caméras cachées de capter le code confidentiel."),
            ExerciseItem(id: UUID(), prompt: "Comment organiser une armoire à pharmacie ?", options: [], correctAnswer: "Matériel : tous les médicaments de la maison, un marqueur, un sac poubelle. Étapes : Tout sortir de l'armoire. Vérifier chaque date de péremption. Trier les médicaments périmés pour les ramener à la pharmacie. Classer par catégorie d'utilisation. Ranger de manière ordonnée. Risques : conserver des médicaments périmés, les ranger dans un endroit trop humide.", explanation: "Vérifier les dates de péremption permet d'éliminer les médicaments qui ont perdu leur efficacité ou qui peuvent devenir dangereux avec le temps."),
            ExerciseItem(id: UUID(), prompt: "Comment retourner un article acheté dans un magasin ?", options: [], correctAnswer: "Matériel : l'article à retourner, le reçu d'achat, l'emballage d'origine. Étapes : Vérifier les conditions et délais de retour du magasin. Se présenter au comptoir du service client avec le reçu. Expliquer la raison du retour. Obtenir le remboursement ou l'échange. Risques : dépasser le délai limite de retour, perdre le reçu.", explanation: "Connaître les conditions et délais de retour avant de se présenter au magasin évite un refus de remboursement pour non-respect de la politique du commerce."),
            ExerciseItem(id: UUID(), prompt: "Comment remplacer la pile d'un détecteur de fumée ?", options: [], correctAnswer: "Matériel : pile neuve de 9 volts, escabeau si nécessaire. Étapes : Retirer le détecteur de son support au plafond. Ouvrir le compartiment de la pile. Enlever l'ancienne pile. Insérer la nouvelle en respectant les polarités plus et moins. Appuyer sur le bouton de test pour vérifier le fonctionnement. Raccrocher le détecteur. Risques : utiliser une mauvaise pile, ne pas tester après installation.", explanation: "Respecter la polarité de la pile est essentiel au bon fonctionnement du détecteur, et tester après installation confirme que l'appareil protège correctement contre les incendies."),
            ExerciseItem(id: UUID(), prompt: "Comment lire les informations nutritionnelles sur un produit alimentaire ?", options: [], correctAnswer: "Trouver : la taille de la portion indiquée en haut de l'étiquette. Noter que toutes les valeurs nutritionnelles listées (calories, lipides, sodium) correspondent à cette portion, et non à l'ensemble du paquet. Comparer à la quantité que vous mangez réellement. Risques : penser que le paquet entier correspond à une seule portion.", explanation: "Les valeurs nutritionnelles affichées correspondent à une portion définie et non à l'emballage entier, une confusion fréquente qui fausse le calcul des calories consommées."),
            ExerciseItem(id: UUID(), prompt: "Comment se débarrasser de manière sûre des médicaments périmés ou inutilisés ?", options: [], correctAnswer: "Méthode : rapporter les médicaments inutilisés dans un point de collecte sécurisé en pharmacie. Si ce n'est pas possible, mélanger les comprimés avec du marc de café usagé ou de la litière pour chat dans un sac fermé avant de les jeter à la poubelle. Risques : jeter les pilules dans les toilettes ou l'évier, polluant ainsi l'eau.", explanation: "Jeter des médicaments dans les toilettes contamine l'eau potable et les écosystèmes ; les points de collecte en pharmacie permettent une élimination sécurisée et contrôlée."),
            ExerciseItem(id: UUID(), prompt: "Comment préparer et envoyer une lettre par la poste ?", options: [], correctAnswer: "Matériel : lettre écrite, enveloppe, timbre postal. Étapes : Plier la lettre en trois. L'insérer dans l'enveloppe. Écrire l'adresse complète du destinataire au centre. Écrire votre adresse de retour en haut à gauche. Coller le timbre en haut à droite. Déposer l'enveloppe dans une boîte aux lettres de la poste. Risques : inverser les adresses, oublier le timbre.", explanation: "Écrire l'adresse du destinataire au centre et celle de l'expéditeur en haut à gauche respecte la convention postale qui permet un tri automatique correct du courrier."),
            ExerciseItem(id: UUID(), prompt: "Comment bien préparer son rendez-vous chez le médecin ?", options: [], correctAnswer: "Matériel : carte d'assurance, pièce d'identité, liste complète des médicaments actuels, carnet de notes avec vos questions. Étapes : Rédiger vos questions à l'avance. Lister tous les traitements avec leurs dosages. Arriver 10 minutes en avance pour remplir les formulaires administratifs. Risques : oublier de mentionner un nouveau symptôme.", explanation: "Préparer ses questions et la liste de ses médicaments à l'avance permet d'utiliser efficacement le temps limité de la consultation médicale."),
            ExerciseItem(id: UUID(), prompt: "Comment classer et ranger vos documents administratifs importants à la maison ?", options: [], correctAnswer: "Méthode : créer des dossiers étiquetés par catégorie (médical, financier, légal, identité). Ranger les documents importants dans un classeur ou une boîte ignifugée et facile d'accès. Risques : mélanger les papiers de différentes années, ne pas pouvoir retrouver rapidement un document en cas d'urgence.", explanation: "Classer les documents par catégorie dans un contenant sécurisé permet de les retrouver rapidement, notamment lors d'une urgence nécessitant une pièce d'identité ou un document médical."),
            ExerciseItem(id: UUID(), prompt: "Comment configurer le paiement automatique pour vos factures d'électricité ou de téléphone ?", options: [], correctAnswer: "Matériel : ordinateur ou smartphone, coordonnées bancaires (numéro de routage et de compte), accès au site du fournisseur. Étapes : Se connecter à son compte en ligne. Aller dans l'onglet 'Paiement automatique'. Saisir ses informations bancaires. Valider et vérifier le courriel de confirmation. Risques : ne pas surveiller le solde de son compte bancaire.", explanation: "Vérifier régulièrement son solde bancaire après avoir activé le paiement automatique évite les découverts en cas de prélèvement imprévu."),
            ExerciseItem(id: UUID(), prompt: "Comment naviguer en voiture vers une nouvelle destination à l'aide du GPS de son téléphone ?", options: [], correctAnswer: "Matériel : smartphone avec application de navigation (GPS), support de téléphone pour voiture. Étapes : Entrer l'adresse de destination complète avant de démarrer le moteur. Fixer le téléphone sur son support. Activer le guidage vocal. Suivre les consignes sans manipuler le téléphone en conduisant. Risques : panne de batterie de téléphone, distraction en conduisant.", explanation: "Entrer la destination avant de démarrer et éviter de manipuler le téléphone en conduisant réduisent le risque de distraction au volant."),
            ExerciseItem(id: UUID(), prompt: "Comment remplir correctement un chèque bancaire ?", options: [], correctAnswer: "Matériel : chèque, stylo non effaçable. Étapes : Écrire la date en haut à droite. Écrire le nom du destinataire après 'Payer à l'ordre de'. Inscrire le montant en chiffres dans la case à droite. Écrire le montant en toutes lettres sur la ligne du milieu. Ajouter une note dans 'Mémo'. Signer le chèque en bas à droite. Risques : laisser le montant en blanc, oublier de signer.", explanation: "Signer le chèque et remplir tous les champs, y compris le montant en lettres, sont nécessaires car un chèque incomplet ou non signé n'est pas valide bancairement."),
            ExerciseItem(id: UUID(), prompt: "Comment trier ses déchets selon les règles de recyclage locales en Californie ?", options: [], correctAnswer: "Méthode : trier en trois bacs différents. Bac bleu pour le recyclage (plastique, papier, verre, métal). Bac vert pour les déchets organiques et restes alimentaires. Bac noir pour les ordures ménagères non recyclables. Risques : jeter des sacs plastiques souples dans le bac bleu, jeter des piles dans la poubelle ordinaire.", explanation: "Le tri par couleur de bac permet aux centres de traitement de séparer efficacement recyclables, déchets organiques et ordures, évitant la contamination des matières recyclables."),
            ExerciseItem(id: UUID(), prompt: "Comment préparer son sac de secours en cas d'alerte d'évacuation (Go-Bag) ?", options: [], correctAnswer: "Matériel : sac à dos robuste. Contenu : bouteilles d'eau, barres énergétiques, médicaments pour 7 jours, copies de documents d'identité importants, lampe de poche, radio à piles, chargeur de téléphone, trousse de premiers soins, vêtements de rechange. Risques : sac trop lourd à porter, médicaments périmés à l'intérieur.", explanation: "Un sac de secours prêt à l'avance avec des documents et des médicaments à jour permet de partir immédiatement lors d'une alerte d'évacuation sans perdre de temps précieux."),
            ExerciseItem(id: UUID(), prompt: "Comment nettoyer un réfrigérateur de manière hygiénique ?", options: [], correctAnswer: "Matériel : éponge, eau tiède, vinaigre blanc ou nettoyant doux. Étapes : Vider entièrement le réfrigérateur. Jeter les produits périmés ou abîmés. Nettoyer les étagères et les tiroirs. Essuyer les parois intérieures. Sécher avec un chiffon propre. Ranger les aliments de manière organisée. Risques : utiliser des produits toxiques, laisser l'eau stagner.", explanation: "Vider et nettoyer régulièrement le réfrigérateur élimine les bactéries issues des aliments périmés qui pourraient contaminer les autres produits stockés."),
            ExerciseItem(id: UUID(), prompt: "Comment faire les courses en ligne avec livraison à domicile pour une personne à mobilité réduite ?", options: [], correctAnswer: "Matériel : ordinateur ou tablette, connexion internet, carte de paiement. Étapes : Choisir un site de supermarché local. Ajouter les articles au panier virtuel. Sélectionner un créneau horaire de livraison. Entrer l'adresse de livraison et les instructions d'accès. Payer en ligne. Risques : commander des produits erronés, être absent au moment de la livraison.", explanation: "Indiquer précisément le créneau et les instructions d'accès évite les livraisons manquées, particulièrement importantes pour une personne à mobilité réduite."),
            ExerciseItem(id: UUID(), prompt: "Comment signaler une panne de réverbère public devant sa maison ?", options: [], correctAnswer: "Matériel : adresse exacte ou numéro du réverbère, téléphone ou ordinateur. Étapes : Repérer le numéro inscrit sur le poteau. Se connecter au site web de la ville ou appeler le service des travaux publics. Signaler la panne en fournissant les détails. Risques : donner une mauvaise adresse, ne pas noter le numéro de suivi du signalement.", explanation: "Relever le numéro inscrit sur le poteau permet aux services municipaux d'identifier précisément le réverbère défectueux à réparer."),
            ExerciseItem(id: UUID(), prompt: "Comment suspendre temporairement la livraison du courrier pendant des vacances ?", options: [], correctAnswer: "Matériel : ordinateur ou formulaire de la poste (USPS). Étapes : Aller sur le site web officiel de la poste au moins 3 jours avant le départ. Remplir la demande d'interruption temporaire du courrier en indiquant les dates de début et de fin. Valider la demande. Risques : faire la demande trop tard, oublier de récupérer son courrier au retour.", explanation: "Faire la demande d'interruption du courrier plusieurs jours à l'avance laisse le temps au bureau de poste de la traiter avant le départ."),
            ExerciseItem(id: UUID(), prompt: "Comment vérifier la pression des pneus d'une voiture ?", options: [], correctAnswer: "Matériel : manomètre de pression de pneu. Étapes : Trouver la pression recommandée sur l'étiquette à l'intérieur de la portière conducteur. Retirer le bouchon de la valve du pneu. Appliquer fermement le manomètre sur la valve pour lire la pression. Ajouter ou enlever de l'air si nécessaire. Risques : rouler avec des pneus sous-gonflés, ce qui augmente le risque d'accident.", explanation: "Vérifier la pression recommandée sur l'étiquette du véhicule plutôt qu'une valeur générique garantit une pression adaptée qui réduit le risque d'éclatement ou de perte d'adhérence."),
            ExerciseItem(id: UUID(), prompt: "Comment nettoyer un filtre de climatiseur ou de purificateur d'air ?", options: [], correctAnswer: "Matériel : aspirateur ou eau tiède et savon doux. Étapes : Éteindre l'appareil. Ouvrir le panneau d'accès et retirer délicatement le filtre. Aspirer la poussière accumulée. Si le filtre est lavable, le passer sous l'eau tiède et le laisser sécher complètement à l'air libre avant de le réinstaller. Risques : réinstaller un filtre encore humide.", explanation: "Laisser sécher complètement un filtre lavable avant de le réinstaller évite le développement de moisissures à l'intérieur de l'appareil."),
            ExerciseItem(id: UUID(), prompt: "Comment réinitialiser le routeur internet (Wi-Fi) après une coupure de connexion ?", options: [], correctAnswer: "Étapes : Débrancher le câble d'alimentation électrique à l'arrière du routeur. Attendre 30 secondes complètes pour permettre aux composants de se décharger. Rebrancher le câble. Attendre 2 à 3 minutes que tous les voyants redeviennent verts stables. Risques : appuyer sur le bouton de réinitialisation d'usine par erreur.", explanation: "Attendre 30 secondes avant de rebrancher le routeur permet aux composants électroniques de se décharger complètement, ce qui est nécessaire pour une réinitialisation efficace."),
            ExerciseItem(id: UUID(), prompt: "Comment bloquer les appels téléphoniques indésirables (démarchage agressif) sur son téléphone portable ?", options: [], correctAnswer: "Méthode : enregistrer son numéro sur la liste nationale d'opposition au démarchage (Do Not Call Registry). Activer l'option de blocage des numéros inconnus ou suspects dans les paramètres du téléphone ou utiliser une application de filtrage fournie par l'opérateur. Risques : bloquer accidentellement un appel légitime d'un médecin.", explanation: "S'inscrire sur la liste nationale d'opposition au démarchage réduit légalement le nombre d'appels commerciaux non sollicités reçus sur son téléphone."),
            ExerciseItem(id: UUID(), prompt: "Comment vérifier le bon fonctionnement d'une sonnette de porte ?", options: [], correctAnswer: "Étapes : Appuyer sur le bouton extérieur de la sonnette. Écouter si le carillon retentit à l'intérieur de la maison. Si aucun son n'est émis, vérifier si les piles du bouton ou du boîtier intérieur sont usées et les remplacer. Si le problème persiste, vérifier les connexions électriques. Risques : ne pas entendre un visiteur important ou un livreur.", explanation: "Vérifier les piles avant de suspecter un problème électrique plus complexe permet d'identifier la cause la plus simple et la plus fréquente d'une sonnette silencieuse."),
            ExerciseItem(id: UUID(), prompt: "Comment utiliser un pèse-personne électronique de manière fiable ?", options: [], correctAnswer: "Étapes : Placer le pèse-personne sur une surface plane et dure (éviter les tapis ou moquettes). Monter dessus pieds nus, en restant bien immobile au centre. Attendre que le chiffre affiché se stabilise. Se peser de préférence le matin à jeun pour des résultats cohérents. Risques : fausses mesures sur sol mou ou inégal.", explanation: "Se peser sur une surface dure et plane évite les variations de mesure causées par un support instable comme un tapis ou une moquette."),
            ExerciseItem(id: UUID(), prompt: "Comment nettoyer des lunettes de vue sans rayer les verres ?", options: [], correctAnswer: "Matériel : eau tiède, une goutte de liquide vaisselle doux, chiffon en microfibre. Étapes : Passer les lunettes sous l'eau tiède. Appliquer une goutte de savon et frotter doucement les verres avec les doigts. Rincer abondamment. Sécher délicatement avec le chiffon microfibre propre. Risques : utiliser sa chemise ou de l'essuie-tout qui peuvent rayer.", explanation: "Utiliser un chiffon en microfibre plutôt qu'un tissu rugueux évite de rayer le revêtement délicat des verres de lunettes."),
            ExerciseItem(id: UUID(), prompt: "Comment économiser l'eau au quotidien dans le jardin en Californie ?", options: [], correctAnswer: "Méthode : arroser uniquement tôt le matin ou après le coucher du soleil pour limiter l'évaporation. Installer un système d'arrosage goutte-à-goutte. Choisir des plantes locales résistantes à la sécheresse. Risques : arroser en plein après-midi sous le soleil chaud, ce qui gaspille l'eau et peut brûler les plantes.", explanation: "Arroser tôt le matin ou le soir limite l'évaporation rapide causée par la chaleur du soleil, ce qui économise l'eau tout en hydratant efficacement les plantes."),
            ExerciseItem(id: UUID(), prompt: "Comment dégivrer un congélateur en toute sécurité ?", options: [], correctAnswer: "Matériel : bassines d'eau chaude, serviettes, glacière temporaire. Étapes : Vider le congélateur et placer les aliments dans la glacière. Débrancher l'appareil. Placer des bols d'eau chaude à l'intérieur et des serviettes au sol pour absorber l'eau. Attendre la fonte complète. Essuyer et rebrancher. Risques : utiliser un couteau pour gratter la glace.", explanation: "Éviter les objets tranchants pour gratter la glace protège les parois internes du congélateur, qui peuvent être facilement percées et endommagées."),
            ExerciseItem(id: UUID(), prompt: "Comment signaler la perte d'une carte de transport en commun ?", options: [], correctAnswer: "Matériel : numéro de compte ou identifiant en ligne de la carte de transport. Étapes : Se connecter au site web de la compagnie de transport (comme BART ou Metro) ou appeler leur service client. Signaler la perte pour désactiver la carte et transférer le solde sur une nouvelle carte. Risques : perdre le solde restant si le signalement est tardif.", explanation: "Signaler rapidement la perte permet de désactiver la carte avant qu'un tiers ne l'utilise et de transférer le solde restant sur une nouvelle carte."),
            ExerciseItem(id: UUID(), prompt: "Comment s'assurer de bien hydrater une personne âgée pendant une journée chaude ?", options: [], correctAnswer: "Méthode : proposer un verre d'eau toutes les heures, même si la personne ne ressent pas la soif. Varier les boissons (tisanes froides, eau citronnée, bouillons légers) et proposer des fruits riches en eau comme le melon ou la pastèque. Risques : attendre que la personne demande à boire, ce qui peut mener à la déshydratation.", explanation: "Proposer de l'eau régulièrement plutôt que d'attendre la demande est important car la sensation de soif diminue avec l'âge, augmentant le risque de déshydratation chez les personnes âgées.")
        ]
    )
}


